/* RCV Analytics - Chart.js helpers  (Chart.js 3.7.x) */

var RCV_COLORS = [
    '#2563eb','#16a34a','#ea580c','#9333ea','#0891b2',
    '#d97706','#dc2626','#059669','#7c3aed','#db2777',
    '#0284c7','#65a30d','#c2410c','#7e22ce','#0e7490',
    '#b45309','#b91c1c','#047857','#6d28d9','#be185d',
];

function rcvGetColors(count) {
    var colors = [];
    for (var i = 0; i < count; i++) {
        colors.push(RCV_COLORS[i % RCV_COLORS.length]);
    }
    return colors;
}

function rcvNoData(canvasId) {
    var box = document.getElementById(canvasId);
    if (!box) return;
    box.style.display = 'none';
    var msg = document.createElement('div');
    msg.style.cssText = 'color:#94a3b8;font-size:.85em;text-align:center;padding:32px 0;';
    msg.textContent = 'Sin datos disponibles';
    box.parentNode.appendChild(msg);
}

/**
 * Dibuja valores numéricos sobre cada barra.
 * Usado como inline plugin afterDraw — se ejecuta en cada render, incluido
 * resize, por lo que las etiquetas siempre son visibles.
 */
function rcvDrawBarLabels(chart) {
    var ctx     = chart.ctx;
    var areaTop = chart.chartArea ? chart.chartArea.top : 0;

    chart.data.datasets.forEach(function(dataset, i) {
        var meta = chart.getDatasetMeta(i);
        if (meta.hidden) return;
        meta.data.forEach(function(bar, index) {
            var value = dataset.data[index];
            if (!value) return;

            /* En Chart.js 3.x bar.x y bar.y son propiedades directas */
            var x = bar.x, y = bar.y;
            if (x === undefined || y === undefined) return;

            /* Si hay ≥16 px de espacio arriba → dibujar encima;
               si no (barra muy alta o chart muy comprimido) → dibujar dentro */
            var textY, baseline;
            if (y - areaTop >= 16) {
                textY    = y - 4;
                baseline = 'bottom';
            } else {
                textY    = y + 14;
                baseline = 'top';
            }

            ctx.save();
            ctx.fillStyle    = '#1e293b';
            ctx.font         = 'bold 11px sans-serif';
            ctx.textAlign    = 'center';
            ctx.textBaseline = baseline;
            ctx.fillText(value, x, textY);
            ctx.restore();
        });
    });
}

/* Plugin inline reutilizable — sin id para evitar conflictos al usarlo en múltiples charts */
function rcvMakeBarLabelPlugin() {
    return {
        afterDraw: function(chart) { rcvDrawBarLabels(chart); }
    };
}

function rcvRenderLineChart(canvasId, chartData, datasetLabel) {
    var ctx = document.getElementById(canvasId);
    if (!ctx || !chartData || !chartData.labels || !chartData.labels.length) { rcvNoData(canvasId); return; }
    try {
    new Chart(ctx, {
        type: 'line',
        data: {
            labels: chartData.labels,
            datasets: [{
                label: datasetLabel || '',
                data: chartData.data,
                borderColor: RCV_COLORS[0],
                backgroundColor: RCV_COLORS[0] + '22',
                fill: true,
                tension: 0.3,
                pointRadius: 4,
            }]
        },
        options: {
            responsive: true,
            maintainAspectRatio: false,
            plugins: { legend: { display: false } },
            scales: { y: { beginAtZero: true, ticks: { precision: 0 } } }
        }
    });
    } catch(e) { console.error('rcvRenderLineChart error:', e); rcvNoData(canvasId); }
}

function rcvRenderBarChart(canvasId, chartData, datasetLabel) {
    var ctx = document.getElementById(canvasId);
    if (!ctx || !chartData || !chartData.labels || !chartData.labels.length) { rcvNoData(canvasId); return; }
    var displayLabels = chartData.labels.map(function(l) {
        return (l && l.length > 25) ? l.substring(0, 22) + '...' : l;
    });
    var maxVal = Math.max.apply(null, chartData.data);
    try {
    new Chart(ctx, {
        type: 'bar',
        data: {
            labels: displayLabels,
            datasets: [{
                label: datasetLabel || '',
                data: chartData.data,
                backgroundColor: rcvGetColors(chartData.data.length),
                borderRadius: 4,
            }]
        },
        options: {
            responsive: true,
            maintainAspectRatio: false,
            interaction: { mode: 'index', intersect: false },
            plugins: {
                legend: { display: false },
                tooltip: {
                    mode: 'index',
                    intersect: false,
                    callbacks: {
                        title: function(items) {
                            return chartData.labels[items[0].dataIndex] || '';
                        }
                    }
                }
            },
            scales: {
                y: {
                    beginAtZero: true,
                    ticks: { precision: 0 },
                    suggestedMax: maxVal > 0 ? Math.ceil(maxVal * 1.2) : 10
                },
                x: { ticks: { maxRotation: 45, minRotation: 0, autoSkip: true, maxTicksLimit: 100, font: { size: 11 } } }
            }
        },
        plugins: [rcvMakeBarLabelPlugin()]
    });
    } catch(e) { console.error('rcvRenderBarChart error:', e); rcvNoData(canvasId); }
}

function rcvRenderDoughnutChart(canvasId, chartData) {
    var ctx = document.getElementById(canvasId);
    if (!ctx || !chartData || !chartData.labels || !chartData.labels.length) { rcvNoData(canvasId); return; }
    try {
    new Chart(ctx, {
        type: 'doughnut',
        data: {
            labels: chartData.labels,
            datasets: [{
                data: chartData.data,
                backgroundColor: rcvGetColors(chartData.data.length),
                borderWidth: 2,
            }]
        },
        options: {
            responsive: true,
            maintainAspectRatio: false,
            plugins: {
                legend: {
                    position: 'bottom',
                    labels: { font: { size: 11 }, boxWidth: 12, padding: 10 }
                }
            }
        }
    });
    } catch(e) { console.error('rcvRenderDoughnutChart error:', e); rcvNoData(canvasId); }
}

function rcvRenderStackedBarChart(canvasId, chartData) {
    /* chartData = { labels:[], datasets:[{label, data:[]},...] } */
    var ctx = document.getElementById(canvasId);
    if (!ctx || !chartData || !chartData.labels || !chartData.labels.length) { rcvNoData(canvasId); return; }
    var ds = chartData.datasets.map(function(d, i) {
        return Object.assign({ backgroundColor: RCV_COLORS[i % RCV_COLORS.length] }, d);
    });
    var maxVal = 0;
    chartData.labels.forEach(function(_, i) {
        var col = ds.reduce(function(s, d) { return s + (d.data[i] || 0); }, 0);
        if (col > maxVal) maxVal = col;
    });
    try {
    new Chart(ctx, {
        type: 'bar',
        data: { labels: chartData.labels, datasets: ds },
        options: {
            responsive: true,
            maintainAspectRatio: false,
            interaction: { mode: 'index', intersect: false },
            plugins: {
                legend: { position: 'bottom', labels: { font: { size: 11 }, boxWidth: 12, padding: 8 } },
                tooltip: { mode: 'index', intersect: false }
            },
            scales: {
                x: { stacked: true },
                y: {
                    stacked: true,
                    beginAtZero: true,
                    ticks: { precision: 0 },
                    suggestedMax: maxVal > 0 ? Math.ceil(maxVal * 1.2) : 10
                }
            }
        },
        plugins: [rcvMakeBarLabelPlugin()]
    });
    } catch(e) { console.error('rcvRenderStackedBarChart error:', e); rcvNoData(canvasId); }
}
